#include <iostream>
#include <iomanip>
#include <vector>

double average(const std::vector<int>& v)
{
    int sum = 0;
    for (int i = 0; i < std::ssize(v); ++i)
        sum += v[i];
    return static_cast<double>(sum) / static_cast<double>(std::ssize(v));
}

int main()
{
    int n;
    std::cin >> n;

    std::vector<int> nums;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        nums.push_back(x);
    }

    std::cout << "Average: "
              << std::fixed << std::setprecision(2)
              << average(nums) << '\n';

    return 0;
}

