solution_code:
#include <iostream>
#include <vector>

void scaleBy(std::vector<int>& v, int factor)
{
    for (int i = 0; i < std::ssize(v); ++i)
        v[i] *= factor;
}

int main()
{
    int n, factor;
    std::cin >> n >> factor;

    std::vector<int> data;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        data.push_back(x);
    }

    scaleBy(data, factor);

    for (int i = 0; i < std::ssize(data); ++i)
        std::cout << data[i] << '\n';

    return 0;
}
